import logo from './logo.svg';
import './App.css';
import React, { useState, useEffect } from 'react';


function App() {

  const [data, setData] = useState('');

  useEffect(() => {
          fetch('http://localhost:5000/api')
              .then((response) => response.json())
              .then((data) => setData(data.message));
      }, []);

      return (
          <div>
              <h1>Demos</h1>
              <p>{data}</p>
          </div>
      );
}

export default App;
